  mode?: "sheet" | "modal"
  variant?: RecordDetailVariant
  tabs?: RecordDetailTab[]
  headerFields?: string[]
  fieldGroups?: RecordDetailFieldGroup[]
  relatedRecords?: RecordDetailRelatedRecord[]
  editable?: boolean
  hiddenFields?: string[]
  titleField?: string
  descriptionField?: string
  identifierField?: string
  statusField?: string
  onClose: () => void
  onRecordChanged: () => void
  onDelete: () => void
  onNext?: () => void
  onPrevious?: () => void
