  variant = "workspace",
  tabs,
  headerFields,
  fieldGroups,
  relatedRecords,
  editable = true,
  hiddenFields,
  titleField,
  descriptionField,
  identifierField,
  statusField,
  onClose,
  onRecordChanged,
  onDelete,
  onNext,
  onPrevious,
  hasPrevious,
  hasNext,
  updateVia,
  updateFunctionName,
  columnLabels,
  foreignKeyLabels,
