    <RecordDetail
      record={record}
      table={table}
      client={client}
      podId={podId}
      mode={editable ? "editable" : "view"}
      variant={variant}
      tabs={tabs}
      headerFields={headerFields}
      fieldGroups={fieldGroups}
      relatedRecords={relatedRecords}
      hiddenFields={hiddenFields}
      titleField={titleField}
      descriptionField={descriptionField}
