function detailOverlayClassName(appearance: LemmaRecordsAppearance, radius: LemmaRecordsRadius) {
  return cn(
    recordsRadiusClassName(radius, "overlay"),
    appearance === "minimal" ? "border-0 bg-background shadow-none" : null,
    appearance === "borderless" ? "border-0 bg-background shadow-xl" : null,
    appearance === "contained" ? "border-border/70 bg-card shadow-xl" : null,
    appearance === "default" ? "border-border/50 bg-card" : null,
  )
}

"use client"

import * as React from "react"
import { cn } from "@/components/lemma/lib/utils"
import { Checkbox } from "@/components/lemma/ui/checkbox"
import type { ColumnSchema, Table } from "lemma-sdk"
import { isSystemField, type EnumColorMap } from "./records-enum-utils"
import {
  displayColumnLabel,
  formatRecordPlainText,
  formatRecordFieldValue,
  pickColumn,
  pickPrimaryColumn,
  pickSecondaryColumns,
  type ColumnLabelMap,
  type ForeignKeyLabelMap,
  type RecordPreviewDisplayOptions,
} from "./records-display-utils"
import { RecordQuickActionButtons, type RecordQuickAction } from "./records-quick-actions"
import {
  recordsRadiusClassName,
  type LemmaRecordsAppearance,
  type LemmaRecordsDensity,
  type LemmaRecordsRadius,
  type LemmaRecordsSurface,
} from "./records-style-utils"

interface ListViewProps {
  records: Record<string, unknown>[]
  table: Table
  visibleColumns?: ColumnSchema[]
  appearance?: LemmaRecordsAppearance
  surface?: LemmaRecordsSurface
  density?: LemmaRecordsDensity
  radius?: LemmaRecordsRadius
  selectedRecords: Set<string>
  selectionEnabled?: boolean
  onSelectRecord?: (id: string) => void
  onRecordClick: (record: Record<string, unknown>) => void
  renderCard?: (record: Record<string, unknown>, columns: ColumnSchema[]) => React.ReactNode
  foreignKeyLabelMap?: ForeignKeyLabelMap
  columnLabels?: ColumnLabelMap
  displayOptions?: RecordPreviewDisplayOptions
  quickActions?: RecordQuickAction[]
  onQuickAction?: (action: RecordQuickAction, record: Record<string, unknown>, index: number) => void
  pendingActionKey?: string | null
  enumColorMap?: EnumColorMap
}

export function ListView({
  records,
  table,
  visibleColumns,
  selectedRecords,
  selectionEnabled = true,
  onSelectRecord,
  onRecordClick,
  renderCard,
  foreignKeyLabelMap,
  columnLabels,
  displayOptions,
  quickActions,
  onQuickAction,
  pendingActionKey,
  enumColorMap,
  appearance = "default",
  surface = appearance === "borderless" ? "inherit" : appearance === "minimal" ? "muted" : "card",
  density = "comfortable",
  radius = "lg",
}: ListViewProps) {
  const pk = table.primary_key_column || "id"
  const columns = visibleColumns ?? table.columns.filter((c) => !isSystemField(c))

  const primaryCol = pickPrimaryColumn(columns, displayOptions?.primaryField)
  const secondaryCols = pickSecondaryColumns(columns, primaryCol, {
    count: 5,
    fields: displayOptions?.secondaryFields,
  })
  const descriptionCol = pickColumn(columns, displayOptions?.descriptionField)
  const badgeCol = pickColumn(columns, displayOptions?.badgeField)
  const showFieldLabels = displayOptions?.showFieldLabels ?? true

  return (
    <div className={cn("flex flex-col", density === "compact" ? "gap-1.5" : density === "spacious" ? "gap-3" : "gap-2")}>
      {records.map((record) => {
        const id = String(record[pk] ?? "")
        const selected = selectedRecords.has(id)
        return (
          <div
            key={id}
            onClick={() => onRecordClick(record)}
            onKeyDown={(event) => {
              if (event.key === "Enter" || event.key === " ") {
                event.preventDefault()
                onRecordClick(record)
              }
            }}
            role="button"
            tabIndex={0}
            className={cn(
              "group cursor-pointer border transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring/40",
              selected
                ? "border-primary/30 bg-primary/5"
                : surface === "card"
                  ? "border-border/50 bg-card/85 hover:border-border/70 hover:bg-card"
                  : surface === "muted"
                    ? "border-border/15 bg-background/65 hover:border-border/30 hover:bg-background/85"
                    : "border-transparent bg-transparent hover:border-border/20 hover:bg-muted/20",
              appearance === "minimal" && (
                selected
                  ? "border-primary/25 bg-primary/5"
                  : "shadow-none"
              ),
              recordsRadiusClassName(radius, "surface"),
            )}
          >
            {renderCard ? (
              <div className="p-4">{renderCard(record, columns)}</div>
            ) : (
              <div className={cn("flex items-start gap-3 px-4", density === "compact" ? "py-2.5" : density === "spacious" ? "py-[1.125rem]" : "py-3.5")}>
                {selectionEnabled ? (
                  <Checkbox
                    checked={selected}
                    onCheckedChange={() => onSelectRecord?.(id)}
                    onClick={(e) => e.stopPropagation()}
                    className="mt-1"
                  />
                ) : null}
                <div className="min-w-0 flex-1">
                  <div className="flex items-start justify-between gap-3">
                    <div className="min-w-0 flex-1">
                      <div className="flex items-center gap-2">
                        <p className="min-w-0 flex-1 truncate text-sm font-medium text-foreground">
                          {formatRecordFieldValue(primaryCol ? record[primaryCol.name] : undefined, primaryCol, foreignKeyLabelMap, enumColorMap)}
                        </p>
                        {badgeCol && record[badgeCol.name] != null && record[badgeCol.name] !== "" ? (
                          <span className={cn("shrink-0", badgeCol.type === "ENUM" ? "contents" : "inline-flex items-center border border-border/50 bg-muted/40 px-2 py-0.5 text-[11px] font-medium text-foreground", badgeCol.type === "ENUM" ? undefined : recordsRadiusClassName(radius, "pill"))}>
                            {formatRecordFieldValue(record[badgeCol.name], badgeCol, foreignKeyLabelMap, enumColorMap)}
                          </span>
                        ) : null}
                      </div>
                      {descriptionCol ? (
                        (() => {
                          const description = formatRecordPlainText(record[descriptionCol.name])
                          if (!description) return null
                          return (
                            <p className="mt-1 line-clamp-2 text-sm text-muted-foreground">
                              {description}
                            </p>
                          )
                        })()
                      ) : null}
                    </div>
                  </div>
                  <div className="mt-1.5 flex flex-wrap items-center gap-x-3 gap-y-1">
                    {secondaryCols.map((col) => {
                      const val = record[col.name]
                      if (val == null || val === "") return null
                      return (
                        <span key={col.name} className="text-xs text-muted-foreground">
                          {showFieldLabels ? <span className="font-medium">{displayColumnLabel(col.name, columnLabels)}:</span> : null}
                          {showFieldLabels ? " " : null}
                          {formatRecordFieldValue(val, col, foreignKeyLabelMap, enumColorMap)}
                        </span>
                      )
                    })}
                  </div>
                  {quickActions?.length && onQuickAction ? (
                    <RecordQuickActionButtons
                      record={record}
                      recordId={id}
                      actions={quickActions}
                      pendingActionKey={pendingActionKey}
                      onRun={(action, index) => onQuickAction(action, record, index)}
                      compact
                      className="mt-2"
                    />
                  ) : null}
                </div>
              </div>
            )}
          </div>
        )
      })}
    </div>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/components/lemma/lib/utils"
import { Card, CardContent } from "@/components/lemma/ui/card"
import { Checkbox } from "@/components/lemma/ui/checkbox"
import type { ColumnSchema } from "lemma-sdk"
import { enumPillClasses, type EnumColorMap } from "./records-enum-utils"
import {
  displayColumnLabel,
  formatRecordPlainText,
  formatRecordFieldValue,
  pickColumn,
  pickPrimaryColumn,
  pickSecondaryColumns,
  type ColumnLabelMap,
  type ForeignKeyLabelMap,
  type RecordPreviewDisplayOptions,
} from "./records-display-utils"
import { RecordQuickActionButtons, type RecordQuickAction } from "./records-quick-actions"
import {
  recordsRadiusClassName,
  type LemmaRecordsAppearance,
  type LemmaRecordsDensity,
  type LemmaRecordsRadius,
} from "./records-style-utils"

interface GroupedViewProps {
  records: Record<string, unknown>[]
  groupByColumn: ColumnSchema
  layout?: "kanban" | "linear"
  appearance?: LemmaRecordsAppearance
  density?: LemmaRecordsDensity
  radius?: LemmaRecordsRadius
  primaryKey: string
  visibleColumns: ColumnSchema[]
  selectedRecords: Set<string>
  selectionEnabled?: boolean
  onSelectRecord?: (id: string) => void
  onRecordClick: (record: Record<string, unknown>) => void
  renderCard?: (record: Record<string, unknown>, columns: ColumnSchema[]) => React.ReactNode
  foreignKeyLabelMap?: ForeignKeyLabelMap
  columnLabels?: ColumnLabelMap
  displayOptions?: RecordPreviewDisplayOptions
  quickActions?: RecordQuickAction[]
  onQuickAction?: (action: RecordQuickAction, record: Record<string, unknown>, index: number) => void
  pendingActionKey?: string | null
  enumColorMap?: EnumColorMap
}

export function GroupedView({
  records,
  groupByColumn,
  layout = "kanban",
  appearance = "default",
  density = "comfortable",
  radius = "lg",
  primaryKey,
  visibleColumns,
  selectedRecords,
  selectionEnabled = true,
  onSelectRecord,
  onRecordClick,
  renderCard,
  foreignKeyLabelMap,
  columnLabels,
  displayOptions,
  quickActions,
  onQuickAction,
  pendingActionKey,
  enumColorMap,
}: GroupedViewProps) {
  const groups = React.useMemo(() => {
    const map = new Map<string, Record<string, unknown>[]>()
    const ungrouped: Record<string, unknown>[] = []

    for (const rec of records) {
      const key = rec[groupByColumn.name]
      if (key == null || key === "") {
        ungrouped.push(rec)
      } else {
        const k = String(key)
        if (!map.has(k)) map.set(k, [])
        map.get(k)!.push(rec)
      }
    }

    const entries: Array<{ label: string; records: Record<string, unknown>[] }> = []
    if (groupByColumn.options?.length) {
      for (const opt of groupByColumn.options) {
        entries.push({ label: opt, records: map.get(opt) ?? [] })
        map.delete(opt)
      }
    }
    for (const [k, recs] of map) {
      entries.push({ label: k, records: recs })
    }
    if (ungrouped.length) {
      entries.push({ label: "Ungrouped", records: ungrouped })
    }

    return entries
  }, [records, groupByColumn])

  const primaryCol = pickPrimaryColumn(visibleColumns, displayOptions?.primaryField)
  const secondaryCols = pickSecondaryColumns(visibleColumns, primaryCol, {
    groupBy: groupByColumn.name,
    count: layout === "kanban" ? 4 : 5,
    fields: displayOptions?.secondaryFields,
  })
  const descriptionCol = pickColumn(visibleColumns, displayOptions?.descriptionField)
  const badgeCol = pickColumn(visibleColumns, displayOptions?.badgeField)
  const showFieldLabels = displayOptions?.showFieldLabels ?? false

  const groupClass = layout === "kanban"
    ? cn("flex min-w-max pb-2", density === "compact" ? "gap-2" : density === "spacious" ? "gap-4" : "gap-3")
    : cn("flex min-w-0 flex-col", density === "compact" ? "gap-2" : density === "spacious" ? "gap-4" : "gap-3")

  const sectionClass = layout === "kanban"
    ? cn(
        "flex max-h-full shrink-0 flex-col",
        recordsRadiusClassName(radius, "surface"),
        density === "compact" ? "w-72" : density === "spacious" ? "w-96" : "w-80",
        appearance === "minimal"
          ? "border-0 bg-transparent"
          : appearance === "borderless"
            ? "border-0 bg-muted/10"
            : "border border-border/50 bg-muted/20",
      )
    : cn(
        "flex min-w-0 flex-col",
        recordsRadiusClassName(radius, "surface"),
        appearance === "minimal"
          ? "border-0 bg-transparent"
          : appearance === "borderless"
            ? "border-0 bg-transparent"
            : "border border-border/50 bg-card",
      )

  return (
    <div className={groupClass}>
      {groups.map((group) => (
        <section
          key={group.label}
          className={sectionClass}
        >
          <div className={cn("flex items-center justify-between gap-3 px-3", appearance === "borderless" ? "border-b-0" : appearance === "minimal" ? "border-b border-border/15" : "border-b border-border/40", density === "compact" ? "py-2" : density === "spacious" ? "py-3" : "py-2.5")}>
            {groupByColumn.options?.length ? (
              <span className={enumPillClasses(group.label, groupByColumn.options!, enumColorMap)}>
                {group.label}
              </span>
            ) : (
              <span className={cn("inline-flex items-center border border-border/50 bg-muted/50 px-2.5 py-1 text-xs font-medium text-foreground", recordsRadiusClassName(radius, "pill"))}>
                {group.label}
              </span>
            )}
            <span className={cn("bg-background px-2 py-0.5 text-xs text-muted-foreground ring-1 ring-border/50", recordsRadiusClassName(radius, "pill"))}>
              {group.records.length}
            </span>
          </div>
          <div className={cn("flex flex-col", density === "compact" ? "gap-1.5 p-1.5" : density === "spacious" ? "gap-3 p-3" : "gap-2 p-2", layout === "kanban" && "overflow-y-auto")}>
            {group.records.length === 0 && (
              <div className={cn("px-3 py-6 text-center text-xs text-muted-foreground", recordsRadiusClassName(radius, "surface"), appearance === "minimal" ? "border border-dashed border-border/25 bg-transparent" : "border border-dashed border-border/60 bg-background/40")}>
                No records
              </div>
            )}
            {group.records.map((record) => {
              const id = String(record[primaryKey] ?? "")
              const selected = selectedRecords.has(id)
              if (renderCard) {
                return (
                  <Card
                    key={id}
                    size="sm"
                    onClick={() => onRecordClick(record)}
                    className={cn(
                      "cursor-pointer transition-colors",
                      selected ? "bg-primary/5 ring-primary/35" : "hover:bg-background hover:ring-foreground/20",
                      appearance === "borderless" && "ring-0 shadow-none",
                      appearance === "minimal" && (
                        selected
                          ? "shadow-none ring-primary/25"
                          : "bg-transparent shadow-none ring-0 hover:bg-muted/30"
                      ),
                      recordsRadiusClassName(radius, "surface"),
                    )}
                  >
                    <CardContent>{renderCard(record, visibleColumns)}</CardContent>
                  </Card>
                )
              }
              return (
                <Card
                  key={id}
                  size="sm"
                  onClick={() => onRecordClick(record)}
                  className={cn(
                    "cursor-pointer transition-colors",
                    selected ? "bg-primary/5 ring-primary/35" : "hover:bg-background hover:ring-foreground/20",
                    appearance === "borderless" && "ring-0 shadow-none",
                    appearance === "minimal" && (
                      selected
                        ? "shadow-none ring-primary/25"
                        : "bg-transparent shadow-none ring-0 hover:bg-muted/30"
                    ),
                    recordsRadiusClassName(radius, "surface"),
                  )}
                >
                  <CardContent className={cn("flex gap-2", layout === "kanban" ? "flex-col" : "items-center", density === "compact" ? "py-2" : density === "spacious" ? "py-4" : null)}>
                    <div className="flex min-w-0 flex-1 items-start gap-2">
                      {selectionEnabled ? (
                        <Checkbox
                          checked={selected}
                          onCheckedChange={() => onSelectRecord?.(id)}
                          onClick={(e) => e.stopPropagation()}
                          className="mt-0.5"
                        />
                      ) : null}
                      <div className="min-w-0 flex-1">
                        <div className="flex items-center gap-2">
                          <span className="min-w-0 flex-1 truncate text-sm font-medium text-foreground">
                            {formatRecordFieldValue(primaryCol ? record[primaryCol.name] : undefined, primaryCol, foreignKeyLabelMap, enumColorMap)}
                          </span>
                          {badgeCol && record[badgeCol.name] != null && record[badgeCol.name] !== "" ? (
                            <span className={cn("shrink-0", badgeCol.type === "ENUM" ? "contents" : "inline-flex items-center border border-border/50 bg-muted/40 px-2 py-0.5 text-[11px] font-medium text-foreground", badgeCol.type === "ENUM" ? undefined : recordsRadiusClassName(radius, "pill"))}>
                              {formatRecordFieldValue(record[badgeCol.name], badgeCol, foreignKeyLabelMap, enumColorMap)}
                            </span>
                          ) : null}
                        </div>
                        {descriptionCol ? (
                          (() => {
                            const description = formatRecordPlainText(record[descriptionCol.name])
                            if (!description) return null
                            return (
                              <p className="mt-1 line-clamp-2 text-xs text-muted-foreground">
                                {description}
                              </p>
                            )
                          })()
                        ) : null}
                      </div>
                    </div>
                    <div className={cn("flex flex-wrap gap-1.5", layout === "kanban" ? (selectionEnabled ? "pl-6" : null) : "justify-end")}>
                      {secondaryCols.map((col) => {
                        const v = record[col.name]
                        if (v == null || v === "") return null
                        return (
                          <span
                            key={col.name}
                            className={cn("max-w-full truncate bg-muted/50 px-1.5 py-0.5 text-xs text-muted-foreground", recordsRadiusClassName(radius, "control"))}
                          >
                            {showFieldLabels ? `${displayColumnLabel(col.name, columnLabels)}: ` : null}
                            {formatRecordFieldValue(v, col, foreignKeyLabelMap, enumColorMap)}
                          </span>
                        )
                      })}
                    </div>
                    {quickActions?.length && onQuickAction ? (
                      <RecordQuickActionButtons
                        record={record}
                        recordId={id}
                        actions={quickActions}
                        pendingActionKey={pendingActionKey}
                        onRun={(action, index) => onQuickAction(action, record, index)}
                        compact
                        className={selectionEnabled ? (layout === "kanban" ? "pl-6" : "pl-6 md:pl-0") : undefined}
                      />
                    ) : null}
                  </CardContent>
                </Card>
              )
            })}
          </div>
        </section>
      ))}
    </div>
  )
}

"use client"

import * as React from "react"
import { Calendar, Grid2X2, Rows3 } from "lucide-react"
import { Checkbox } from "@/components/lemma/ui/checkbox"
import type { ColumnSchema, Table } from "lemma-sdk"
import { cn } from "@/components/lemma/lib/utils"
import { isSystemField, type EnumColorMap } from "./records-enum-utils"
import {
  displayColumnLabel,
  formatRecordFieldValue,
  formatRecordPlainText,
  pickColumn,
  pickPrimaryColumn,
  pickSecondaryColumns,
  type ColumnLabelMap,
  type ForeignKeyLabelMap,
  type RecordPreviewDisplayOptions,
} from "./records-display-utils"
import { RecordQuickActionButtons, type RecordQuickAction } from "./records-quick-actions"
import {
  recordsRadiusClassName,
  type LemmaRecordsAppearance,
  type LemmaRecordsDensity,
  type LemmaRecordsRadius,
} from "./records-style-utils"

interface ConsolidatedViewBaseProps {
  records: Record<string, unknown>[]
  table: Table
  visibleColumns: ColumnSchema[]
  primaryKey: string
  selectedRecords: Set<string>
  selectionEnabled?: boolean
  onSelectRecord?: (id: string) => void
  onRecordClick: (record: Record<string, unknown>) => void
  foreignKeyLabelMap?: ForeignKeyLabelMap
  columnLabels?: ColumnLabelMap
  displayOptions?: RecordPreviewDisplayOptions
  quickActions?: RecordQuickAction[]
  onQuickAction?: (action: RecordQuickAction, record: Record<string, unknown>, index: number) => void
  pendingActionKey?: string | null
  enumColorMap?: EnumColorMap
  appearance: LemmaRecordsAppearance
  density: LemmaRecordsDensity
  radius: LemmaRecordsRadius
}

export interface RecordsCalendarViewProps extends ConsolidatedViewBaseProps {
  dateField?: string
}

export interface RecordsTimelineViewProps extends ConsolidatedViewBaseProps {
  dateField?: string
}

export interface RecordsMatrixViewProps extends ConsolidatedViewBaseProps {
  rowField?: string
  columnField?: string
}

export function RecordsCalendarView({
  records,
  table,
  visibleColumns,
  primaryKey,
  selectedRecords,
  selectionEnabled = true,
  onSelectRecord,
  onRecordClick,
  foreignKeyLabelMap,
  columnLabels,
  displayOptions,
  quickActions,
  onQuickAction,
  pendingActionKey,
  enumColorMap,
  appearance,
  density,
  radius,
  dateField,
}: RecordsCalendarViewProps) {
  const [cursor, setCursor] = React.useState(() => startOfMonth(new Date()))
  const dateColumn = pickDateColumn(visibleColumns, table.columns, dateField)
  const monthCells = React.useMemo(() => buildMonthCells(cursor), [cursor])
  const recordsByDay = React.useMemo(() => {
    const groups = new Map<string, Record<string, unknown>[]>()
    if (!dateColumn) return groups

    for (const record of records) {
      const date = coerceDate(record[dateColumn.name])
      if (!date) continue
      const key = dayKey(date)
      const group = groups.get(key) ?? []
      group.push(record)
      groups.set(key, group)
    }

    return groups
  }, [dateColumn, records])

  if (!dateColumn) {
    return (
      <MissingViewConfig
        icon={Calendar}
        title="Pick a date field for calendar"
        description="Pass calendarField or include a DATE/DATETIME column such as due_date, starts_at, created_at, or updated_at."
        appearance={appearance}
        radius={radius}
      />
    )
  }

  return (
    <div className="flex min-w-[48rem] flex-col">
      <div className={cn("flex items-center justify-between border-b border-border/30", density === "compact" ? "px-3 py-2" : "px-4 py-3")}>
        <div>
          <p className="text-sm font-medium text-foreground">
            {cursor.toLocaleDateString(undefined, { month: "long", year: "numeric" })}
          </p>
          <p className="text-xs text-muted-foreground">
            Scheduled by {displayColumnLabel(dateColumn.name, columnLabels)}
          </p>
        </div>
        <div className="flex items-center gap-1">
          <button
            type="button"
            className={cn("border border-border/50 bg-background px-2 py-1 text-xs text-muted-foreground hover:bg-muted hover:text-foreground", recordsRadiusClassName(radius, "control"))}
            onClick={() => setCursor(addMonths(cursor, -1))}
          >
            Previous
          </button>
          <button
            type="button"
            className={cn("border border-border/50 bg-background px-2 py-1 text-xs text-muted-foreground hover:bg-muted hover:text-foreground", recordsRadiusClassName(radius, "control"))}
            onClick={() => setCursor(startOfMonth(new Date()))}
          >
            Today
          </button>
          <button
            type="button"
            className={cn("border border-border/50 bg-background px-2 py-1 text-xs text-muted-foreground hover:bg-muted hover:text-foreground", recordsRadiusClassName(radius, "control"))}
            onClick={() => setCursor(addMonths(cursor, 1))}
          >
            Next
          </button>
        </div>
      </div>
      <div className="grid grid-cols-7 border-b border-border/30 bg-muted/20 text-[11px] font-medium uppercase tracking-widest text-muted-foreground">
        {["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"].map((day) => (
          <div key={day} className="px-3 py-2">{day}</div>
        ))}
      </div>
      <div className="grid grid-cols-7">
        {monthCells.map((day) => {
          const key = dayKey(day)
          const dayRecords = recordsByDay.get(key) ?? []
          const isMuted = day.getMonth() !== cursor.getMonth()
          const isToday = key === dayKey(new Date())

          return (
            <div
              key={key}
              className={cn(
                "min-h-36 border-b border-r border-border/25 p-2",
                isMuted ? "bg-muted/10 text-muted-foreground" : "bg-background/40",
              )}
            >
              <div className="mb-2 flex items-center justify-between">
                <span className={cn("flex size-6 items-center justify-center text-xs font-medium", isToday ? "bg-primary text-primary-foreground" : "text-muted-foreground", recordsRadiusClassName(radius, "pill"))}>
                  {day.getDate()}
                </span>
                {dayRecords.length > 0 ? (
                  <span className="text-[11px] text-muted-foreground">{dayRecords.length}</span>
                ) : null}
              </div>
              <div className="flex flex-col gap-1">
                {dayRecords.slice(0, 4).map((record) => (
                  <RecordMiniCard
                    key={String(record[primaryKey] ?? "")}
                    record={record}
                    primaryKey={primaryKey}
                    columns={visibleColumns}
                    selectedRecords={selectedRecords}
                    selectionEnabled={selectionEnabled}
                    onSelectRecord={onSelectRecord}
                    onRecordClick={onRecordClick}
                    foreignKeyLabelMap={foreignKeyLabelMap}
                    columnLabels={columnLabels}
                    displayOptions={displayOptions}
                    quickActions={quickActions}
                    onQuickAction={onQuickAction}
                    pendingActionKey={pendingActionKey}
                    enumColorMap={enumColorMap}
                    density="compact"
                    radius={radius}
                  />
                ))}
                {dayRecords.length > 4 ? (
                  <span className="px-2 py-1 text-xs text-muted-foreground">+{dayRecords.length - 4} more</span>
                ) : null}
              </div>
            </div>
          )
        })}
      </div>
    </div>
  )
}

export function RecordsTimelineView({
  records,
  table,
  visibleColumns,
  primaryKey,
  selectedRecords,
  selectionEnabled = true,
  onSelectRecord,
  onRecordClick,
  foreignKeyLabelMap,
  columnLabels,
  displayOptions,
  quickActions,
  onQuickAction,
  pendingActionKey,
  enumColorMap,
  appearance,
  density,
  radius,
  dateField,
}: RecordsTimelineViewProps) {
  const dateColumn = pickDateColumn(visibleColumns, table.columns, dateField)
  const sortedRecords = React.useMemo(() => {
    if (!dateColumn) return records
    return [...records].sort((a, b) => {
      const aDate = coerceDate(a[dateColumn.name])?.getTime() ?? Number.POSITIVE_INFINITY
      const bDate = coerceDate(b[dateColumn.name])?.getTime() ?? Number.POSITIVE_INFINITY
      return aDate - bDate
    })
  }, [dateColumn, records])

  if (!dateColumn) {
    return (
      <MissingViewConfig
        icon={Rows3}
        title="Pick a date field for timeline"
        description="Pass timelineField or include a DATE/DATETIME column such as due_date, starts_at, created_at, or updated_at."
        appearance={appearance}
        radius={radius}
      />
    )
  }

  return (
    <div className={cn("flex flex-col", density === "compact" ? "gap-2" : "gap-3")}>
      {sortedRecords.map((record, index) => {
        const date = coerceDate(record[dateColumn.name])
        return (
          <div key={String(record[primaryKey] ?? index)} className="grid grid-cols-[7.5rem_minmax(0,1fr)] gap-3">
            <div className="pt-1 text-right">
              <p className="text-xs font-medium text-foreground">
                {date ? date.toLocaleDateString(undefined, { month: "short", day: "numeric" }) : "No date"}
              </p>
              <p className="mt-0.5 text-[11px] text-muted-foreground">
                {date ? date.toLocaleDateString(undefined, { year: "numeric" }) : displayColumnLabel(dateColumn.name, columnLabels)}
              </p>
            </div>
            <div className="grid grid-cols-[auto_minmax(0,1fr)] gap-3">
              <div className="flex flex-col items-center">
                <span className={cn("flex size-7 items-center justify-center border border-border/50 bg-background text-muted-foreground", recordsRadiusClassName(radius, "pill"))}>
                  <Calendar className="size-3.5" />
                </span>
                {index < sortedRecords.length - 1 ? <span className="my-1 h-full min-h-8 w-px bg-border/50" /> : null}
              </div>
              <RecordMiniCard
                record={record}
                primaryKey={primaryKey}
                columns={visibleColumns}
                selectedRecords={selectedRecords}
                selectionEnabled={selectionEnabled}
                onSelectRecord={onSelectRecord}
                onRecordClick={onRecordClick}
                foreignKeyLabelMap={foreignKeyLabelMap}
                columnLabels={columnLabels}
                displayOptions={displayOptions}
                quickActions={quickActions}
                onQuickAction={onQuickAction}
                pendingActionKey={pendingActionKey}
                enumColorMap={enumColorMap}
                density={density}
                radius={radius}
              />
            </div>
          </div>
        )
      })}
    </div>
  )
}

export function RecordsMatrixView({
  records,
  table,
  visibleColumns,
  primaryKey,
  selectedRecords,
  selectionEnabled = true,
  onSelectRecord,
  onRecordClick,
  foreignKeyLabelMap,
  columnLabels,
  displayOptions,
  quickActions,
  onQuickAction,
  pendingActionKey,
  enumColorMap,
  appearance,
  density,
  radius,
  rowField,
  columnField,
}: RecordsMatrixViewProps) {
  const rowColumn = pickMatrixColumn(visibleColumns, table.columns, rowField)
  const columnColumn = pickMatrixColumn(
    visibleColumns.filter((column) => column.name !== rowColumn?.name),
    table.columns.filter((column) => column.name !== rowColumn?.name),
    columnField,
  )
  const matrix = React.useMemo(() => buildMatrix(records, rowColumn, columnColumn), [columnColumn, records, rowColumn])

  if (!rowColumn || !columnColumn) {
    return (
      <MissingViewConfig
        icon={Grid2X2}
        title="Pick two grouping fields for matrix"
        description="Pass matrixRowsBy and matrixColumnsBy, or include at least two enum, status, owner, type, or stage fields."
        appearance={appearance}
        radius={radius}
      />
    )
  }

  return (
    <div className="min-w-[56rem] overflow-auto">
      <div
        className="grid"
        style={{ gridTemplateColumns: `minmax(9rem, 12rem) repeat(${matrix.columnKeys.length}, minmax(14rem, 1fr))` }}
      >
        <div className={cn("sticky left-0 z-10 border-b border-r border-border/40 bg-card px-3 py-2", recordsRadiusClassName(radius, "surface"))}>
          <p className="text-xs font-medium text-foreground">{displayColumnLabel(rowColumn.name, columnLabels)}</p>
          <p className="text-[11px] text-muted-foreground">by {displayColumnLabel(columnColumn.name, columnLabels)}</p>
        </div>
        {matrix.columnKeys.map((columnKey) => (
          <div key={columnKey} className="border-b border-r border-border/40 bg-muted/20 px-3 py-2">
            <p className="truncate text-xs font-medium text-foreground">{columnKey}</p>
            <p className="text-[11px] text-muted-foreground">{matrix.columnTotals.get(columnKey) ?? 0} records</p>
          </div>
        ))}
        {matrix.rowKeys.map((rowKey) => (
          <React.Fragment key={rowKey}>
            <div className="sticky left-0 z-10 border-b border-r border-border/40 bg-card px-3 py-3">
              <p className="truncate text-sm font-medium text-foreground">{rowKey}</p>
              <p className="text-xs text-muted-foreground">{matrix.rowTotals.get(rowKey) ?? 0} records</p>
            </div>
            {matrix.columnKeys.map((columnKey) => {
              const cellRecords = matrix.cells.get(`${rowKey}\u0000${columnKey}`) ?? []
              return (
                <div key={`${rowKey}:${columnKey}`} className={cn("min-h-36 border-b border-r border-border/30 bg-background/30", density === "compact" ? "p-1.5" : "p-2")}>
                  {cellRecords.length === 0 ? (
                    <div className={cn("flex h-full min-h-28 items-center justify-center border border-dashed border-border/40 text-xs text-muted-foreground", recordsRadiusClassName(radius, "surface"))}>
                      Empty
                    </div>
                  ) : (
                    <div className="flex flex-col gap-1.5">
                      {cellRecords.slice(0, 5).map((record) => (
                        <RecordMiniCard
                          key={String(record[primaryKey] ?? "")}
                          record={record}
                          primaryKey={primaryKey}
                          columns={visibleColumns}
                          selectedRecords={selectedRecords}
                          selectionEnabled={selectionEnabled}
                          onSelectRecord={onSelectRecord}
                          onRecordClick={onRecordClick}
                          foreignKeyLabelMap={foreignKeyLabelMap}
                          columnLabels={columnLabels}
                          displayOptions={displayOptions}
                          quickActions={quickActions}
                          onQuickAction={onQuickAction}
                          pendingActionKey={pendingActionKey}
                          enumColorMap={enumColorMap}
                          density="compact"
                          radius={radius}
                        />
                      ))}
                      {cellRecords.length > 5 ? (
                        <span className="px-2 py-1 text-xs text-muted-foreground">+{cellRecords.length - 5} more</span>
                      ) : null}
                    </div>
                  )}
                </div>
              )
            })}
          </React.Fragment>
        ))}
      </div>
    </div>
  )
}

function RecordMiniCard({
  record,
  primaryKey,
  columns,
  selectedRecords,
  selectionEnabled = true,
  onSelectRecord,
  onRecordClick,
  foreignKeyLabelMap,
  columnLabels,
  displayOptions,
  quickActions,
  onQuickAction,
  pendingActionKey,
  enumColorMap,
  density,
  radius,
}: {
  record: Record<string, unknown>
  primaryKey: string
  columns: ColumnSchema[]
  selectedRecords: Set<string>
  selectionEnabled?: boolean
  onSelectRecord?: (id: string) => void
  onRecordClick: (record: Record<string, unknown>) => void
  foreignKeyLabelMap?: ForeignKeyLabelMap
  columnLabels?: ColumnLabelMap
  displayOptions?: RecordPreviewDisplayOptions
  quickActions?: RecordQuickAction[]
  onQuickAction?: (action: RecordQuickAction, record: Record<string, unknown>, index: number) => void
  pendingActionKey?: string | null
  enumColorMap?: EnumColorMap
  density: LemmaRecordsDensity
  radius: LemmaRecordsRadius
}) {
  const id = String(record[primaryKey] ?? "")
  const primaryColumn = pickPrimaryColumn(columns, displayOptions?.primaryField)
  const secondaryColumns = pickSecondaryColumns(columns, primaryColumn, {
    count: density === "compact" ? 2 : 3,
    fields: displayOptions?.secondaryFields,
  })
  const descriptionColumn = pickColumn(columns, displayOptions?.descriptionField)
  const selected = selectedRecords.has(id)

  return (
    <div
      role="button"
      tabIndex={0}
      className={cn(
        "group w-full border bg-card text-left transition-colors hover:bg-muted/35",
        selected ? "border-primary/35 bg-primary/5" : "border-border/40",
        recordsRadiusClassName(radius, "surface"),
        density === "compact" ? "p-2" : "p-3",
      )}
      onClick={() => onRecordClick(record)}
      onKeyDown={(event) => {
        if (event.key === "Enter" || event.key === " ") {
          event.preventDefault()
          onRecordClick(record)
        }
      }}
    >
      <span className="flex min-w-0 items-start gap-2">
        {selectionEnabled ? (
          <Checkbox
            checked={selected}
            onCheckedChange={() => onSelectRecord?.(id)}
            onClick={(event) => event.stopPropagation()}
            className="mt-0.5 size-3.5"
          />
        ) : null}
        <span className="min-w-0 flex-1">
          <span className="block truncate text-sm font-medium text-foreground">
            {formatRecordFieldValue(primaryColumn ? record[primaryColumn.name] : undefined, primaryColumn, foreignKeyLabelMap, enumColorMap)}
          </span>
          {descriptionColumn ? (
            <span className="mt-1 line-clamp-2 text-xs text-muted-foreground">
              {formatRecordPlainText(record[descriptionColumn.name])}
            </span>
          ) : null}
          <span className="mt-1.5 flex flex-wrap gap-1">
            {secondaryColumns.map((column) => {
              const value = record[column.name]
              if (value == null || value === "") return null
              return (
                <span key={column.name} className={cn("max-w-full truncate bg-muted/45 px-1.5 py-0.5 text-[11px] text-muted-foreground", recordsRadiusClassName(radius, "control"))}>
                  <span className="font-medium">{displayColumnLabel(column.name, columnLabels)}:</span>{" "}
                  {formatRecordFieldValue(value, column, foreignKeyLabelMap, enumColorMap)}
                </span>
              )
            })}
          </span>
          {quickActions?.length && onQuickAction ? (
            <RecordQuickActionButtons
              record={record}
              recordId={id}
              actions={quickActions}
              pendingActionKey={pendingActionKey}
              onRun={(action, index) => onQuickAction(action, record, index)}
              compact
              className="mt-2"
            />
          ) : null}
        </span>
      </span>
    </div>
  )
}

function MissingViewConfig({
  icon: Icon,
  title,
  description,
  appearance,
  radius,
}: {
  icon: React.ComponentType<{ className?: string }>
  title: string
  description: string
  appearance: LemmaRecordsAppearance
  radius: LemmaRecordsRadius
}) {
  return (
    <div className={cn("flex min-h-64 flex-col items-center justify-center gap-3 border border-dashed border-border/40 px-6 py-8 text-center", appearance === "minimal" ? "bg-transparent" : "bg-muted/15", recordsRadiusClassName(radius, "surface"))}>
      <span className={cn("flex size-10 items-center justify-center border border-border/50 bg-muted/35 text-muted-foreground", recordsRadiusClassName(radius, "pill"))}>
        <Icon className="size-4" />
      </span>
